# Resolvers
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

@strawberry.type
class Query:
    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[ProductType]:
        db = info.context.get("db")
        return db.query(Product).filter(Product.id == id).first()
    
    @strawberry.field
    def products(self, info: Info) -> List[ProductType]:
        db = info.context.get("db")
        return db.query(Product).all()
    
